fn solve(s: String) -> String {
    let mut result: Vec<char> = Vec::new();
    for c in s.chars() {
        match c {
            'a'..='z' => result.push(c),
            '*' => {
                if !result.is_empty() {
                    result.pop();
                }
            },
            '#' => {
                let mut new_result = result.clone();
                result.extend(new_result);
            },
            '%' => {
                result.reverse();
            },
            _ => {}
        }
    }
    result.into_iter().collect()
}
```

